def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0.0
        if ratio > 8:
            for a in range(8, 4, -1):
                for b in range(1, a + 5):
                    val = ((ratio - a) ** 6) / ((a + b) * 1.1 + 1)
                    trig = np.sin(ratio * b / (a + 2)) * np.cos(ratio / (b + 1))
                    priority += val * trig * (np.log1p(ratio + b))**1.2
            priority += np.exp(ratio - 7) * np.cos(ratio * 1.3) ** 2.1
        elif 5 < ratio <= 8:
            for c in range(2, int(np.ceil(ratio)) + 5):
                for d in range(1, c + 3):
                    base = ((ratio - c) ** 4) * np.tanh(ratio * c) / (d + 0.7)
                    priority += np.sin(base * ratio) * 1.7
            priority += np.log(ratio) * 12 - np.tanh(ratio - 5) * 3.1
        elif 2 <= ratio <= 5:
            total = 0.0
            for e in range(1, 15):
                total += ((ratio - 2) ** e) / (e * 2.1) * np.sin(e * ratio * 1.1)
            priority = total * np.cos(9 * ratio) - np.log(ratio + 0.01) * 7 + np.tanh(3 * (5 - ratio)) * 2.4
        elif 1 <= ratio < 2:
            acc = 0.0
            for f in range(1, 13):
                acc += ((2 - ratio) ** f) / (f ** 2 + 1) + np.cos(f * ratio * 2)
            if bin_cap < item * 1.05:
                penalty = np.sqrt(item / (bin_cap + 0.3)) * 5
            else:
                penalty = np.sin(22 * ratio) * 3.1
            priority = acc + penalty + np.exp(-2 / (ratio + 0.07))
            for g in range(1, 7):
                priority += np.cos(g * ratio * i) * ((ratio - 1) ** g) / (g + 0.6)
        elif 0.5 <= ratio < 1:
            sum_s = 0.0
            for h in range(1, 20):
                sum_s += ((1 - ratio) ** h) / (h * 3.9)
            priority = sum_s
            if (i + int(item * 2)) % 5 == 0:
                priority *= np.log1p(bin_cap + 4) * 1.7
            else:
                priority /= (np.sqrt(bin_cap + 2.2) + 3.1)
            for j in range(1, 8):
                priority += ((1 - ratio) ** j) * np.sin(j * item * 1.6) * 0.9
        elif 0.2 <= ratio < 0.5:
            acc_s = 0.0
            for k in range(1, 16):
                acc_s += ((0.5 - ratio) ** k) / (k * 3) * np.cos(k * ratio * 3)
            priority = acc_s + 1 / (bin_cap + 4)
            if int(item * 1.7) % 5 == 0:
                priority *= 3.2
            else:
                priority /= 3.7
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 4.8
            else:
                priority -= np.exp(-ratio * 1.8) * 3.7
            for l in range(1, 9):
                priority += ((0.5 - ratio) ** l) / (l * 5) * np.cos(item * l * 1.3)
        else:
            summ = 0.0
            for m in range(1, 11):
                summ += ((0.2 - ratio) ** m) / (m * 6) * np.sin(m * item * 1.0)
            priority = summ + 3 / (bin_cap + 5)
            if int(item * 0.8) % 7 == 0:
                priority *= 3.7
            else:
                priority /= 4.1
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 6.5
            else:
                priority -= np.exp(-ratio * 2.5) * 5
            for n in range(1, 10):
                priority += ((0.2 - ratio) ** n) / (n * 8) * np.cos(item * n * 0.85)
        if bin_cap < item * 0.5:
            priority += np.log1p(item ** 3 * bin_cap) * 6.5
        elif bin_cap > item * 3.0:
            priority -= np.exp(-4 * ratio) * 5.2
        for o in range(1, 6):
            if (i + o) % 4 == 0:
                priority += np.sin(ratio * (i + o) * 1.5) * 0.4
            else:
                priority -= np.cos(ratio * (i + o) * 1.5) * 0.4
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.4) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.4) * 0.7
        if (i * bin_cap) % 2 == 0:
            priority += np.tanh(ratio * bin_cap / (item + 1)) * 3.3
        else:
            priority -= np.tanh(item / (bin_cap + 1)) * 3.3
        if priority > 1e4:
            priority = np.log(priority + 1) * 500
        elif priority < -1e4:
            priority = -np.log(-priority + 1) * 500
        priorities[i] = priority
    return priorities
